import axios from "axios";
import { config } from "../../utils/axiosconfig";
import { base_url } from "../../utils/baseUrl";

const getB2bCustomers = async (params) => {
  const response = await axios.get(`${base_url}b2b/admin/customers`, {
    ...config,
    params,
  });
  return response.data;
};

const getB2bCustomerDetail = async (id) => {
  const response = await axios.get(`${base_url}b2b/admin/customers/${id}`, config);
  return response.data;
};

const verifyCustomer = async ({ id, action, reason }) => {
  const response = await axios.put(`${base_url}b2b/admin/customers/${id}/verify`, { action, reason }, config);
  return response.data;
};

const setCustomerCredit = async ({ id, creditLimit, paymentTerms }) => {
  const response = await axios.put(`${base_url}b2b/admin/customers/${id}/credit`, { creditLimit, paymentTerms }, config);
  return response.data;
};

const getAdminB2bOrders = async (params) => {
  const response = await axios.get(`${base_url}b2b/admin/orders`, {
    ...config,
    params,
  });
  return response.data;
};

const getB2bOrderDetail = async (id) => {
  const response = await axios.get(`${base_url}b2b/orders/${id}`, config);
  return response.data;
};

const approveB2bOrder = async (id) => {
  const response = await axios.put(`${base_url}b2b/admin/orders/${id}/approve`, {}, config);
  return response.data;
};

const updateB2bOrderStatus = async ({ id, status, deliveredQuantities, proformaInvoiceUrl, taxInvoiceUrl }) => {
  const response = await axios.put(
    `${base_url}b2b/admin/orders/${id}/status`,
    { status, deliveredQuantities, proformaInvoiceUrl, taxInvoiceUrl },
    config
  );
  return response.data;
};

const setB2bTrackingNumber = async ({ id, trackingNumber }) => {
  const response = await axios.put(`${base_url}b2b/admin/orders/${id}/tracking`, { trackingNumber }, config);
  return response.data;
};

