export const resetB2bState = createAction("b2b/reset-state");

const initialState = {
  customers: [],
  customerDetail: null,
  b2bProducts: [],
  b2bProductsMeta: null,
  orders: [],
  orderDetail: null,
  rfqs: [],
  rfqDetail: null,
  kpis: null,
  salesAnalytics: null,
  inventoryAnalytics: null,
  customerAnalytics: null,
  expiringProducts: null,
  lowStockProducts: null,
  isLoading: false,
  isError: false,
  isSuccess: false,
  message: "",
};

export const b2bSlice = createSlice({
  name: "b2b",
  initialState,
  reducers: {},
  extraReducers: (builder) => {
    builder
      // Reset
      .addCase(resetB2bState, () => initialState)

      // Customers
      .addCase(getB2bCustomers.pending, (state) => { state.isLoading = true; })
      .addCase(getB2bCustomers.fulfilled, (state, action) => {
        state.isLoading = false;
        state.isError = false;
        state.isSuccess = true;
        state.customers = action.payload.data;
        state.meta = action.payload.meta;
      })
      .addCase(getB2bCustomers.rejected, (state, action) => {
        state.isLoading = false;
        state.isError = true;
        state.message = action.payload || action.error.message;
      })

      .addCase(getB2bCustomerDetail.pending, (state) => { state.isLoading = true; })
      .addCase(getB2bCustomerDetail.fulfilled, (state, action) => {
        state.isLoading = false;
        state.isSuccess = true;
        state.customerDetail = action.payload.data;
      })
      .addCase(getB2bCustomerDetail.rejected, (state, action) => {
        state.isLoading = false;
        state.isError = true;
        state.message = action.payload || action.error.message;
      })

      .addCase(verifyCustomer.fulfilled, (state, action) => {
        state.isSuccess = true;
        if (state.customerDetail && state.customerDetail.id === action.payload.data.id) {
          state.customerDetail.isVerified = action.payload.data.isVerified;
          state.customerDetail.b2bApprovedAt = action.payload.data.b2bApprovedAt;
        }
        state.customers = state.customers.map((c) =>
          c.id === action.payload.data.id ? { ...c, isVerified: action.payload.data.isVerified } : c
        );
      })

      .addCase(setCustomerCredit.fulfilled, (state, action) => {
        state.isSuccess = true;
        if (state.customerDetail && state.customerDetail.id === action.payload.data.id) {
          state.customerDetail.creditLimit = action.payload.data.creditLimit;
          state.customerDetail.paymentTerms = action.payload.data.paymentTerms;
        }
        state.customers = state.customers.map((c) =>
          c.id === action.payload.data.id
            ? { ...c, creditLimit: action.payload.data.creditLimit, paymentTerms: action.payload.data.paymentTerms }
            : c
        );
      })

      // Orders
      .addCase(getAdminB2bOrders.pending, (state) => { state.isLoading = true; })
      .addCase(getAdminB2bOrders.fulfilled, (state, action) => {
        state.isLoading = false;
        state.orders = action.payload.data;
        state.meta = action.payload.meta;
      })
      .addCase(getAdminB2bOrders.rejected, (state, action) => {
        state.isLoading = false;
        state.isError = true;
        state.message = action.payload || action.error.message;
      })

      .addCase(getB2bOrderDetail.pending, (state) => { state.isLoading = true; })
      .addCase(getB2bOrderDetail.fulfilled, (state, action) => {
        state.isLoading = false;
        state.orderDetail = action.payload.data;
      })
      .addCase(getB2bOrderDetail.rejected, (state, action) => {
        state.isLoading = false;
        state.isError = true;
        state.message = action.payload || action.error.message;
      })

      .addCase(approveB2bOrder.fulfilled, (state, action) => {
        if (state.orderDetail && state.orderDetail.id === action.payload.data.id) {
          state.orderDetail.procurementStatus = action.payload.data.procurementStatus;
          state.orderDetail.status = action.payload.data.status;
        }
        state.orders = state.orders.map((o) =>
          o.id === action.payload.data.id
            ? { ...o, procurementStatus: action.payload.data.procurementStatus, status: action.payload.data.status }
            : o
        );
      })

      .addCase(updateB2bOrderStatus.fulfilled, (state, action) => {
        state.orderDetail = action.payload.data;
        state.orders = state.orders.map((o) =>
          o.id === action.payload.data.id ? action.payload.data : o
        );
      })

      .addCase(setB2bTrackingNumber.fulfilled, (state, action) => {
        if (state.orderDetail && state.orderDetail.id === action.payload.data.id) {
          state.orderDetail.shipmentTrackingNumber = action.payload.data.shipmentTrackingNumber;
        }
        state.orders = state.orders.map((o) =>
          o.id === action.payload.data.id ? { ...o, shipmentTrackingNumber: action.payload.data.shipmentTrackingNumber } : o
        );
      })

      // RFQs
      .addCase(getAdminRfqs.pending, (state) => { state.isLoading = true; })
      .addCase(getAdminRfqs.fulfilled, (state, action) => {
        state.isLoading = false;
        state.rfqs = action.payload.data;
        state.meta = action.payload.meta;
      })
      .addCase(getAdminRfqs.rejected, (state, action) => {
        state.isLoading = false;
        state.isError = true;
        state.message = action.payload || action.error.message;
      })

      .addCase(getRfqDetail.pending, (state) => { state.isLoading = true; })
      .addCase(getRfqDetail.fulfilled, (state, action) => {
        state.isLoading = false;
        state.rfqDetail = action.payload.data;
      })
      .addCase(getRfqDetail.rejected, (state, action) => {
        state.isLoading = false;
        state.isError = true;
        state.message = action.payload || action.error.message;
      })

      .addCase(respondToRfq.fulfilled, (state, action) => {
        state.rfqDetail = action.payload.data;
        state.rfqs = state.rfqs.map((r) =>
          r.id === action.payload.data.id ? action.payload.data : r
        );
      })

      // Analytics & Alerts
      .addCase(getOverviewKPIs.fulfilled, (state, action) => {
        state.kpis = action.payload.data;
      })
      .addCase(getSalesAnalytics.fulfilled, (state, action) => {
        state.salesAnalytics = action.payload.data;
      })
      .addCase(getInventoryAnalytics.fulfilled, (state, action) => {
        state.inventoryAnalytics = action.payload.data;
      })
      .addCase(getCustomerAnalytics.fulfilled, (state, action) => {
        state.customerAnalytics = action.payload.data;
      })
      .addCase(getExpiringSoonProducts.fulfilled, (state, action) => {
        state.expiringProducts = action.payload.data;
      })
      .addCase(getLowStockProducts.fulfilled, (state, action) => {
        state.lowStockProducts = action.payload.data;
      })

      // Admin B2B Products
      .addCase(getAdminB2bProducts.pending, (state) => { state.isLoading = true; })
      .addCase(getAdminB2bProducts.fulfilled, (state, action) => {
        state.isLoading = false;
        state.isError = false;
        state.b2bProducts = action.payload.data;
        state.b2bProductsMeta = action.payload.meta;
      })
      .addCase(getAdminB2bProducts.rejected, (state, action) => {
        state.isLoading = false;
        state.isError = true;
        state.message = action.payload || action.error.message;
      });
  },
});

export default b2bSlice.reducer;
